174	      customer: { name: "Test Customer", years: 0, contracts: 0 },
175	      steps: [
176	        { type: "quote", items: [{ type: "Sword", material: "steel", enchantment: 9 }] },
177	        { type: "claim", policy: 0, incident: { damages: [{ itemType: "Sword", amount: 1000 }] } },
