1	// claim-office.ts
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  Sword: 100,
5	  Amulet: 60,
6	  Staff: 80,
7	  Potion: 40,
8	  Rune: 25,
9	  Moonstone: 25,
10	};
11	
12	const INSURANCE_VALUES: Record<string, number> = {
13	  Sword: 1000,
14	  Amulet: 600,
15	  Staff: 800,
16	  Potion: 400,
17	  Rune: 250,
18	  Moonstone: 250,
19	};
20	
21	const FIRST_INSURANCE_PERCENT = 110;
22	const PROCESSING_FEE = 5;
23	const DEDUCTIBLE_PER_DAMAGE = 100;
24	const CAP_MULTIPLIER = 2;
25	
26	type Item = { type: string; cursed?: boolean; enchantment?: number };
27	type Customer = { name: string; years: number; contracts: number };
28	
29	const LOYALTY_YEARS_THRESHOLD = 2;
30	const LOYALTY_DISCOUNT_RATE = 0.2;
31	
32	const COMPONENT_TYPES = new Set(["Rune", "Moonstone"]);
33	const BLOCK_OF_3_BASE_PREMIUM = 60;
34	const BLOCK_OF_3_SIZE = 3;
35	const CURSED_SURCHARGE_RATE = 0.5;
36	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
37	const HIGH_ENCHANTMENT_THRESHOLD = 5;
38	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
39	const HIGH_ENCHANTMENT_CLAIM_REIMBURSEMENT_RATE = 0.5;
40	
41	const enchantmentLevelOf = (item: Item | undefined): number =>
42	  item?.enchantment ?? 0;
43	
44	const isBlockOf3Components = (type: string, count: number): boolean =>
45	  COMPONENT_TYPES.has(type) && count === BLOCK_OF_3_SIZE;
46	
47	const baseForGroup = (type: string, count: number): number =>
48	  isBlockOf3Components(type, count)
49	    ? BLOCK_OF_3_BASE_PREMIUM
50	    : BASE_PREMIUMS[type] * count;
51	
52	const countItemsByType = (items: Item[]): Record<string, number> =>
53	  items.reduce<Record<string, number>>((counts, item) => {
54	    counts[item.type] = (counts[item.type] ?? 0) + 1;
55	    return counts;
56	  }, {});
57	
58	const baseTotalFor = (items: Item[]): number =>
59	  Object.entries(countItemsByType(items))
60	    .reduce((total, [type, count]) => total + baseForGroup(type, count), 0);
61	
62	const surchargeOnBase = (item: Item, applies: boolean, rate: number): number =>
63	  applies ? BASE_PREMIUMS[item.type] * rate : 0;
64	
65	const cursedSurchargeFor = (item: Item): number =>
66	  surchargeOnBase(item, item.cursed === true, CURSED_SURCHARGE_RATE);
67	
68	const highEnchantmentSurchargeFor = (item: Item): number =>
69	  surchargeOnBase(item, enchantmentLevelOf(item) >= HIGH_ENCHANTMENT_THRESHOLD, HIGH_ENCHANTMENT_SURCHARGE_RATE);
70	
71	const itemSurchargesFor = (items: Item[]): number =>
72	  items.reduce((total, item) => total + cursedSurchargeFor(item) + highEnchantmentSurchargeFor(item), 0);
73	
74	const loyaltyDiscountFor = (customer: Customer, baseTotal: number): number =>
75	  customer.years >= LOYALTY_YEARS_THRESHOLD ? baseTotal * LOYALTY_DISCOUNT_RATE : 0;
76	
77	const applyFirstInsurance = (baseTotal: number): number =>
78	  (baseTotal * FIRST_INSURANCE_PERCENT) / 100;
79	
80	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
81	
82	const followUpDiscountFor = (isFollowUp: boolean, baseTotal: number): number =>
83	  isFollowUp ? baseTotal * FOLLOW_UP_DISCOUNT_RATE : 0;
84	
85	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
86	  const baseTotal = baseTotalFor(items);
87	  const policyBase = applyFirstInsurance(baseTotal);
88	  const itemSurcharges = itemSurchargesFor(items);
89	  const loyaltyDiscount = loyaltyDiscountFor(customer, baseTotal);
90	  const followUpDiscount = followUpDiscountFor(isFollowUp, baseTotal);
91	  return Math.ceil(policyBase + itemSurcharges - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
92	};
93	
94	type Policy = { items: Item[]; cap: number; remainingCap: number };
95	type Damage = { itemType: string; amount: number };
96	type ClaimStep = { type: "claim"; policy: number; incident: { damages: Damage[] } };
97	type QuoteStep = { type: "quote"; items: Item[] };
98	type Step = QuoteStep | ClaimStep;
99	type Scenario = { customer: Customer; steps: Step[] };
100	type ClaimResult = { payout: number; remainingCap: number };
101	type QuoteResult = { premium: number };
102	
103	const insuranceSumFor = (items: Item[]): number =>
104	  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
105	
106	const payoutForDamage = (damage: Damage, items: Item[]): number => {
107	  const item = items.find((i) => i.type === damage.itemType);
108	  const isHighEnchantmentClaim = enchantmentLevelOf(item) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
109	  const reimbursable = isHighEnchantmentClaim
110	    ? damage.amount * HIGH_ENCHANTMENT_CLAIM_REIMBURSEMENT_RATE
111	    : damage.amount;
112	  return Math.max(0, reimbursable - DEDUCTIBLE_PER_DAMAGE);
113	};
114	
115	const totalPayoutFor = (damages: Damage[], items: Item[]): number =>
116	  Math.floor(damages.reduce((total, damage) => total + payoutForDamage(damage, items), 0));
117	
118	const clampToCap = (amount: number, remainingCap: number): number =>
119	  Math.min(amount, remainingCap);
120	
121	const processClaim = (step: ClaimStep, policies: Policy[]): ClaimResult => {
122	  const policy = policies[step.policy];
123	  const payout = clampToCap(totalPayoutFor(step.incident.damages, policy.items), policy.remainingCap);
124	  policy.remainingCap -= payout;
125	  return { payout, remainingCap: policy.remainingCap };
126	};
127	
128	const newPolicyFor = (items: Item[]): Policy => {
129	  const cap = CAP_MULTIPLIER * insuranceSumFor(items);
130	  return { items, cap, remainingCap: cap };
131	};
132	
133	const processQuote = (step: QuoteStep, customer: Customer, isFollowUp: boolean, policies: Policy[]): QuoteResult => {
134	  policies.push(newPolicyFor(step.items));
135	  return { premium: quotePremium(step.items, customer, isFollowUp) };
136	};
137	
138	export function processScenario(scenario: any): unknown {
139	  const policies: Policy[] = [];
140	  const results = (scenario.steps as Step[]).map((step, index) =>
141	    step.type === "claim"
142	      ? processClaim(step, policies)
143	      : processQuote(step, scenario.customer, index > 0, policies),
144	  );
145	  return { results };
146	}
